// 🧠 Mood & Intent Analysis Engine (Therapist Style)

// Detect mood + user intent from text
export const analyzeMood = (text) => {
  const lowerText = text.toLowerCase();

  // 🟡 Mood keywords
  const moodKeywords = {
    happy: ["happy", "good", "great", "excited", "joy", "love", "relieved"],
    sad: ["sad", "down", "depressed", "lonely", "cry", "tired", "hopeless"],
    anxious: [
      "anxious",
      "worried",
      "stress",
      "stressed",
      "panic",
      "scared",
      "afraid",
      "overwhelmed",
      "pressure",
      "tense"
    ],
    angry: ["angry", "frustrated", "mad", "irritated", "annoyed"],
    calm: ["calm", "relaxed", "peaceful", "okay"],
  };

  // 🟣 Intent keywords (VERY IMPORTANT)
  const intentKeywords = {
    wantsAdvice: ["what should i do", "solution", "help me", "advice", "suggest"],
    wantsToVent: ["just want to say", "listen", "vent", "tell you"],
    wantsSongs: ["song", "music", "playlist"],
    explanation: ["because", "due to", "reason", "happened"],
  };

  let detectedMood = "neutral";
  let confidence = 0;

  for (const [mood, keywords] of Object.entries(moodKeywords)) {
    const matches = keywords.filter(word => lowerText.includes(word)).length;
    if (matches > confidence) {
      confidence = matches;
      detectedMood = mood;
    }
  }

  // Detect intent
  let intent = "continue";
  for (const [key, words] of Object.entries(intentKeywords)) {
    if (words.some(word => lowerText.includes(word))) {
      intent = key;
    }
  }

  return {
    mood: detectedMood,
    intent,
    timestamp: new Date().toLocaleString(),
    source: "text",
  };
};

// 😊 Facial emotion support (unchanged but improved mapping)
export const analyzeFacialMood = (expressions) => {
  if (!expressions) {
    return { mood: "neutral", confidence: 0, source: "face" };
  }

  let detectedMood = "neutral";
  let maxScore = 0;

  const emotionMap = {
    happy: expressions.happy || 0,
    sad: expressions.sad || 0,
    angry: expressions.angry || 0,
    anxious: expressions.fearful || 0,
    neutral: expressions.neutral || 0
  };

  for (const [emotion, score] of Object.entries(emotionMap)) {
    if (score > maxScore) {
      maxScore = score;
      detectedMood = emotion;
    }
  }

  return {
    mood: detectedMood,
    confidence: Math.round(maxScore * 100),
    timestamp: new Date().toLocaleString(),
    source: "face",
  };
};

// 💾 Save mood history
export const saveMood = (moodData) => {
  const history = JSON.parse(localStorage.getItem("moodHistory")) || [];
  history.push(moodData);

  if (history.length > 30) history.shift();

  localStorage.setItem("moodHistory", JSON.stringify(history));
};
